import { useParams } from 'react-router-dom'
import { connect } from 'react-redux'

const DummyShowComments = ( props ) => {
	let {slug} = useParams()

	return(
			<div className='p-5'>
			<h2 className='text-center pb-4'>Comments</h2>
			{
			props.state.filter((item) => item.postUrl === slug ).map((item, index) => 
			item.comments.length > 0 ?
			item.comments.map((item, index)=> 
				<div key={index} className='text-center border-top pt-2' >
					<h4 >@{item.userName}</h4>
					<p className=''>{item.userComment}</p>
					<p className='text-end text-muted m-1'>{item.date}</p>
				</div>
				)
				: <h4 key={index}>No comment yet</h4>
			)
			}
			</div>
	)
}
const mapStateToProps = ( state ) => {
	return {
		state: state.postState,
		}
}
export default connect(mapStateToProps)(DummyShowComments)
